# Module defining shape classes with inheritance and interface implementation
from module_utils import IDrawable, IMeasurable, Point

@abstract
class Shape:
    position: Point
    color: str

    def __init__(self, position: Point, color: str):
        self.position = position
        self.color = color

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def draw(self) -> str:
        ...

    def describe(self) -> str:
        return f"Shape at ({self.position.x}, {self.position.y}) with color {self.color}"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, position: Point, width: float, height: float, color: str):
        super().__init__(position, color)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def draw(self) -> str:
        return f"Rectangle({self.width}x{self.height})"

class Circle(Shape):
    radius: float

    def __init__(self, position: Point, radius: float, color: str):
        super().__init__(position, color)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def draw(self) -> str:
        return f"Circle(r={self.radius})"

