# Module providing operations on shapes
from module_utils import format_measurement, SHAPE_RECTANGLE, SHAPE_CIRCLE, Point
from module_shapes import Shape, Rectangle, Circle

class ShapeCalculator:
    shapes: list[Shape]

    def __init__(self):
        self.shapes = []

    def add_shape(self, shape: Shape) -> None:
        self.shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total = total + shape.area()
        return total

    def get_shape_report(self) -> str:
        lines: list[str] = []
        for shape in self.shapes:
            lines.append(f"{shape.draw()}: {format_measurement(shape.area(), 'sq units')}")
        return ", ".join(lines)

def create_sample_shape(shape_type: int, x: float, y: float) -> Shape:
    pos: Point = Point(x, y)
    if shape_type == SHAPE_RECTANGLE:
        return Rectangle(pos, 10.0, 5.0, "blue")
    elif shape_type == SHAPE_CIRCLE:
        return Circle(pos, 7.0, "red")
    else:
        return Rectangle(pos, 1.0, 1.0, "green")
